+	test("Ctrl-F moves cursor forward", async () => {
+		let submitted = "";
+		const { stdin } = render(
+			<InputArea
+				onSubmit={(text) => {
+					submitted = text;
+				}}
+				onSlashCommand={() => {}}
+				isRunning={false}
+			/>,
+		);
+		stdin.write("abc");
+		await flush();
+		stdin.write("\x01"); // Ctrl-A (go to start)
+		await flush();
+		stdin.write("\x06"); // Ctrl-F (forward one)
+		await flush();
+		stdin.write("X");
+		await flush();
+		stdin.write("\r");
+		await flush();
+		expect(submitted).toBe("aXbc");
+	});
